import { useEffect } from 'react';
import React from 'react';
import { useNavigate } from 'react-router-dom';

function Home() {
  const navigate = useNavigate();

  return (
    <div style={styles.container}>

      {/* HEADER COM LOGO */}
      <button onClick={() => {
  localStorage.removeItem('user');
  window.location.href = '/';
}}>
  Sair
</button>
      <div style={styles.header}>
        <img src="/logo.png" alt="GRC" style={styles.logo} />
        <span style={styles.systemName}>Sistema GRC</span>
      </div>

      {/* CARD CENTRAL */}
      <div style={styles.card}>
        <h1 style={styles.title}>Sistema de Gestão de Reclamações</h1>

        <p style={styles.subtitle}>
          Painel corporativo para gestão, controle e tratativa de demandas
        </p>

        <div style={styles.buttons}>
          <button
            style={styles.primaryButton}
            onClick={() => navigate('/cadastro')}
          >
            ➕ Nova Reclamação
          </button>

          <button
            style={styles.secondaryButton}
            onClick={() => navigate('/dashboard')}
          >
            📊 Dashboard / Gestão
          </button>
        </div>
      </div>

    </div>
  );
}

const styles = {
  container: {
    height: '100vh',
    background: 'linear-gradient(135deg, #1e3c72, #2a5298)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center'
  },

  header: {
    position: 'absolute',
    top: 20,
    left: 20,
    display: 'flex',
    alignItems: 'center',
    gap: 10
  },

  logo: {
    width: 80
  },

  systemName: {
    color: '#fff',
    fontWeight: 'bold',
    fontSize: 18
  },

  card: {
    background: '#fff',
    padding: 40,
    borderRadius: 12,
    width: 420,
    boxShadow: '0 15px 40px rgba(0,0,0,0.2)',
    textAlign: 'center'
  },

  title: {
    marginBottom: 10,
    color: '#1e3c72'
  },

  subtitle: {
    fontSize: 14,
    color: '#666',
    marginBottom: 30
  },

  buttons: {
    display: 'flex',
    flexDirection: 'column',
    gap: 15
  },

  primaryButton: {
    padding: 15,
    background: '#1e88e5',
    color: '#fff',
    border: 'none',
    borderRadius: 8,
    fontSize: 16,
    cursor: 'pointer'
  },

  secondaryButton: {
    padding: 15,
    background: '#43a047',
    color: '#fff',
    border: 'none',
    borderRadius: 8,
    fontSize: 16,
    cursor: 'pointer'
  }
};

export default Home;
